492	function fmt(n, decimals) {
493	  if (n == null || isNaN(n)) return '--';
494	  decimals = decimals != null ? decimals : 2;
495	  return Number(n).toLocaleString(undefined, { minimumFractionDigits: decimals, maximumFractionDigits: decimals });
