662	
663	  // Separate HOLD from actionable signals
664	  const actionable = signals.filter(s => s.direction && s.direction.toUpperCase() !== 'HOLD');
665	  const holdCount = signals.length - actionable.length;
666	
667	  // Sort by confidence descending
668	  actionable.sort((a, b) => (b.confidence || 0) - (a.confidence || 0));
669	
670	  if (!actionable.length) {
