680	    html += '<tr>'
681	      + '<td>' + escHtml(s.instrument) + '</td>'
682	      + '<td class="' + dirClass(s.direction) + '">' + escHtml(s.direction) + '</td>'
683	      + '<td>' + (s.confidence != null ? (s.confidence * 100).toFixed(1) + '%' : '--') + '</td>'
684	      + '<td style="' + sentColor + '">' + (sent != null ? Number(sent).toFixed(2) : '--') + '</td>'
685	      + '<td>' + (s.rsi_14 != null ? Number(s.rsi_14).toFixed(1) : '--') + '</td>'
686	      + '<td>' + (s.macd != null ? Number(s.macd).toFixed(4) : '--') + '</td>'
687	      + '<td>' + (s.adx != null ? Number(s.adx).toFixed(1) : '--') + '</td>'
688	      + '</tr>';
689	  });
690	  html += '</tbody></table>';
691	  if (holdCount) {
692	    html += '<p style="font-size:0.78rem;color:var(--text-dim);margin-top:8px">' + holdCount + ' instrument' + (holdCount !== 1 ? 's' : '') + ' on HOLD (hidden)</p>';
693	  }
694	  wrap.innerHTML = html;
