723	      + '<td>' + (t.exit_price != null ? fmt(t.exit_price, 5) : '--') + '</td>'
724	      + '<td style="' + pnlColor + ';font-family:var(--mono)">' + (pnl != null ? (pnl >= 0 ? '+' : '') + fmt(pnl, 4) : '--') + '</td>'
725	      + '<td>' + statusText + '</td>'
726	      + '<td>' + (t.confidence != null ? (t.confidence * 100).toFixed(1) + '%' : '--') + '</td>'
727	      + '</tr>';
728	  });
729	  html += '</tbody></table>';
730	  if (closedCount > 0) {
