893	/* ── Technical Indicators ── */
894	async function refreshIndicators() {
895	  const data = await fetchJSON('/api/indicators');
896	  const wrap = document.getElementById('indicatorGrid');
897	  if (!data || !Object.keys(data).length) { wrap.innerHTML = '<p class="no-data">No indicator data</p>'; return; }
898	
899	  function bar(val, min, max, color) {
900	    const pct = Math.max(0, Math.min(100, ((val - min) / (max - min)) * 100));
901	    return '<div class="gauge-bar"><div class="gauge-fill" style="width:' + pct.toFixed(1) + '%;background:' + color + '"></div></div>';
902	  }
903	  function bipolar(val, absMax, posColor, negColor) {
904	    const clamped = Math.max(-absMax, Math.min(absMax, val));
905	    const pct = Math.abs(clamped) / absMax * 50;
906	    const left = clamped >= 0 ? 50 : 50 - pct;
907	    const color = clamped >= 0 ? posColor : negColor;
908	    return '<div class="gauge-bar-bipolar"><div class="gauge-center"></div><div class="gauge-fill-bi" style="left:' + left.toFixed(1) + '%;width:' + pct.toFixed(1) + '%;background:' + color + '"></div></div>';
909	  }
910	
911	  let html = '';
912	  Object.keys(data).forEach(inst => {
913	    const d = data[inst];
914	    const rsi = d.rsi_14;
915	    const rsiColor = rsi != null ? (rsi < 30 ? 'var(--green)' : rsi > 70 ? 'var(--red)' : 'var(--text-dim)') : 'var(--text-dim)';
916	    const bbColor = d.bb_percent_b != null ? (d.bb_percent_b < 0.2 ? 'var(--green)' : d.bb_percent_b > 0.8 ? 'var(--red)' : 'var(--accent)') : 'var(--text-dim)';
917	    const adxColor = d.adx != null && d.adx > 25 ? 'var(--green)' : 'var(--text-dim)';
918	
919	    html += '<div class="indicator-row">'
920	      + '<span class="indicator-row-label">' + escHtml(inst) + '</span>'
921	      + '<div class="gauge-group">'
922	      + '<div class="mini-gauge"><span class="mini-gauge-label">RSI 14</span>' + bar(rsi || 50, 0, 100, rsiColor) + '<span class="gauge-value" style="color:' + rsiColor + '">' + (rsi != null ? rsi.toFixed(1) : '--') + '</span></div>'
923	      + '<div class="mini-gauge"><span class="mini-gauge-label">BB %B</span>' + bar((d.bb_percent_b || 0.5) * 100, 0, 100, bbColor) + '<span class="gauge-value">' + (d.bb_percent_b != null ? d.bb_percent_b.toFixed(2) : '--') + '</span></div>'
924	      + '<div class="mini-gauge"><span class="mini-gauge-label">ADX</span>' + bar(d.adx || 0, 0, 60, adxColor) + '<span class="gauge-value" style="color:' + adxColor + '">' + (d.adx != null ? d.adx.toFixed(1) : '--') + '</span></div>'
925	      + '<div class="mini-gauge"><span class="mini-gauge-label">MACD</span>' + bipolar(d.macd_histogram || 0, 0.005, 'var(--green)', 'var(--red)') + '<span class="gauge-value">' + (d.macd_histogram != null ? d.macd_histogram.toFixed(5) : '--') + '</span></div>'
926	      + '</div></div>';
