931	/* ── Decision Waterfall ── */
932	async function refreshWaterfall() {
933	  const data = await fetchJSON('/api/scoring-breakdown');
934	  const wrap = document.getElementById('waterfallList');
935	  if (!data || !Object.keys(data).length) { wrap.innerHTML = '<p class="no-data">No scoring data</p>'; return; }
936	
937	  let html = '';
938	  Object.keys(data).forEach(inst => {
939	    const d = data[inst];
940	    const comps = d.components || [];
941	    const nonMult = comps.filter(c => !c.is_multiplier);
942	    const totalAbs = nonMult.reduce((s, c) => s + Math.abs(c.score || 0), 0) || 1;
943	    const dirCls = dirClass(d.direction);
944	    const confPct = d.confidence != null ? (d.confidence * 100).toFixed(1) + '%' : '--';
945	
946	    let barHtml = '';
947	    let detailHtml = '';
948	    nonMult.forEach(c => {
949	      const w = (Math.abs(c.score || 0) / totalAbs * 100);
950	      const color = (c.score || 0) >= 0 ? 'var(--green)' : 'var(--red)';
951	      barHtml += '<div class="waterfall-seg" style="width:' + w.toFixed(1) + '%;background:' + color + '" title="' + escHtml(c.name) + ': ' + (c.score != null ? c.score.toFixed(3) : '') + '">' + (w > 8 ? escHtml(c.name) : '') + '</div>';
952	      detailHtml += '<div class="waterfall-detail-row"><span>' + escHtml(c.name) + (c.is_multiplier ? ' (mult)' : '') + '</span><span style="font-family:var(--mono)">val: ' + (c.value != null ? Number(c.value).toFixed(4) : '--') + ' &rarr; score: <span style="color:' + color + '">' + (c.score != null ? c.score.toFixed(3) : '--') + '</span></span></div>';
953	    });
954	    comps.filter(c => c.is_multiplier).forEach(c => {
955	      detailHtml += '<div class="waterfall-detail-row"><span>' + escHtml(c.name) + ' <span style="color:var(--accent)">(multiplier)</span></span><span style="font-family:var(--mono)">val: ' + (c.value != null ? Number(c.value).toFixed(4) : '--') + ' &rarr; &times;' + (c.score != null ? c.score.toFixed(3) : '--') + '</span></div>';
956	    });
957	
958	    html += '<div class="waterfall-item">'
959	      + '<div class="waterfall-header" onclick="toggleWaterfall(this)">'
960	      + '<span class="waterfall-label">' + escHtml(inst) + '</span>'
961	      + '<div class="waterfall-summary"><span class="' + dirCls + '">' + escHtml(d.direction || 'HOLD') + '</span><span style="font-family:var(--mono)">' + confPct + '</span><span class="waterfall-arrow">&#9654;</span></div>'
962	      + '</div>'
963	      + '<div class="waterfall-body">'
964	      + '<div class="waterfall-bar-track">' + barHtml + '</div>'
965	      + detailHtml
966	      + '</div></div>';
967	  });
968	  wrap.innerHTML = html;
969	}
