1111	/* ── Bot Summary ── */
1112	function refreshSummary() {
1113	  const el = document.getElementById('botSummary');
1114	  const eng = _lastEngineStatus;
1115	  const signals = _lastSignals || [];
1116	  const btn = document.getElementById('startStopBtn');
1117	  const isStopped = btn && btn.classList.contains('stopped');
1118	
1119	  if (isStopped && !(eng && eng.halted)) {
1120	    el.textContent = 'Bot is stopped.';
1121	    return;
1122	  }
1123	  if (eng && eng.halted) {
1124	    el.innerHTML = '<span style="color:#ff9800">\u26A0 TRADING HALTED: ' + escHtml(eng.halt_reason || 'Circuit breaker triggered') + '</span>';
1125	    return;
1126	  }
1127	
1128	  const actionable = signals.filter(s => s.direction && s.direction.toUpperCase() !== 'HOLD');
1129	  const totalInstruments = signals.length;
1130	  const cycles = eng ? (eng.cycle_count || 0) : 0;
1131	  const tradeCount = _lastTrade ? 'at least 1' : '0';
1132	
1133	  if (actionable.length > 0) {
1134	    actionable.sort((a, b) => (b.confidence || 0) - (a.confidence || 0));
1135	    const top = actionable[0];
1136	    const confPct = top.confidence != null ? (top.confidence * 100).toFixed(1) + '%' : '?';
1137	    el.textContent = 'Watching ' + actionable.length + ' potential trade' + (actionable.length !== 1 ? 's' : '')
1138	      + '. Strongest: ' + (top.instrument || '?') + ' ' + (top.direction || '?') + ' at ' + confPct + ' confidence. '
1139	      + cycles + ' cycle' + (cycles !== 1 ? 's' : '') + ' completed.';
1140	  } else {
1141	    el.textContent = 'Analyzing ' + totalInstruments + ' instrument' + (totalInstruments !== 1 ? 's' : '')
1142	      + '. No actionable signals this cycle.';
1143	  }
1144	}
