1146	/* ── Alert Banner ── */
1147	function refreshAlertBanner() {
1148	  const banner = document.getElementById('alertBanner');
1149	  const eng = _lastEngineStatus;
1150	
1151	  // Check for halt
1152	  if (eng && eng.halted) {
1153	    showBanner('\u26A0 Trading halted: ' + (eng.halt_reason || 'Circuit breaker triggered'), 'halted');
1154	    return;
1155	  }
1156	
1157	  // Check for recent trade (within 60 seconds)
1158	  if (_lastTrade && _lastTrade.timestamp) {
1159	    const tradeTime = new Date(_lastTrade.timestamp).getTime();
1160	    const now = Date.now();
1161	    const tradeId = _lastTrade.trade_id || _lastTrade.id || _lastTrade.timestamp;
1162	    if ((now - tradeTime) < 60000 && tradeId !== _lastAlertTradeId) {
1163	      _lastAlertTradeId = tradeId;
1164	      const t = _lastTrade;
1165	      const msg = '\u2713 Trade executed: ' + (t.direction || '') + ' ' + (t.instrument || '') + ' '
1166	        + (t.units != null ? fmt(t.units, 0) + ' units' : '') + (t.price != null ? ' at ' + fmt(t.price, 5) : '');
1167	      showBanner(msg, 'trade');
1168	      return;
1169	    }
1170	  }
1171	}
